/**
 * StatusBar Component
 * Displays current crosshair coordinates and mouse hover coordinates
 * Shows coordinate system label (LPI)
 */

import React from 'react';
import { useViewStateStore } from '@/stores/viewStateStore';
import { useEvent } from '@/events/EventBus';

interface StatusBarProps {
  className?: string;
}

export function StatusBar({ className = '' }: StatusBarProps) {
  const crosshair = useViewStateStore(state => state.viewState.crosshair);
  const [mouseCoord, setMouseCoord] = React.useState<[number, number, number] | null>(null);

  // Listen for mouse coordinate updates
  useEvent('mouse.worldCoordinate', React.useCallback((data: { coord: [number, number, number] | null }) => {
    setMouseCoord(data.coord);
  }, []));

  // Format coordinates for display
  const formatCoord = (coord: [number, number, number]) => {
    return `${coord[0].toFixed(1)}, ${coord[1].toFixed(1)}, ${coord[2].toFixed(1)}`;
  };

  return (
    <div className={`bg-gray-900 border-t border-gray-700 px-4 py-2 flex items-center justify-between text-sm ${className}`}>
      <div className="flex items-center space-x-6">
        {/* Coordinate system label */}
        <div className="text-gray-400">
          <span className="font-medium">Coordinate System:</span>{' '}
          <span className="text-gray-300">LPI</span>
        </div>

        {/* Crosshair coordinates */}
        <div className="text-gray-400">
          <span className="font-medium">Crosshair:</span>{' '}
          <span className="text-gray-300 font-mono">
            ({formatCoord(crosshair.world_mm)})
          </span>
        </div>

        {/* Mouse coordinates */}
        {mouseCoord && (
          <div className="text-gray-400">
            <span className="font-medium">Mouse:</span>{' '}
            <span className="text-gray-300 font-mono">
              ({formatCoord(mouseCoord)})
            </span>
          </div>
        )}
      </div>

      {/* Optional right side content */}
      <div className="text-gray-500 text-xs">
        Brainflow v2
      </div>
    </div>
  );
}

/**
 * StatusBar Component
 * Displays current crosshair world coordinates and mouse hover coordinates
 * Shows coordinate system (LPI) and real-time updates
 */

import React from 'react';
import { useViewStateStore } from '@/stores/viewStateStore';
import { useEvent } from '@/events/EventBus';

interface StatusBarProps {
  className?: string;
}

export function StatusBar({ className = '' }: StatusBarProps) {
  const crosshair = useViewStateStore(state => state.viewState.crosshair);
  const [mouseCoord, setMouseCoord] = React.useState<[number, number, number] | null>(null);

  // Listen for mouse coordinate events
  useEvent('mouse.worldCoordinate', (data) => {
    setMouseCoord(data.world_mm);
  });

  useEvent('mouse.leave', () => {
    setMouseCoord(null);
  });

  // Format coordinates for display
  const formatCoord = (coord: [number, number, number]) => {
    return `(${coord[0].toFixed(1)}, ${coord[1].toFixed(1)}, ${coord[2].toFixed(1)})`;
  };

  return (
    <div className={`fixed bottom-0 left-0 right-0 bg-gray-900 border-t border-gray-700 text-gray-300 text-sm px-4 py-2 flex items-center justify-between ${className}`}>
      <div className="flex items-center gap-6">
        {/* Coordinate system label */}
        <div className="flex items-center gap-2">
          <span className="text-gray-500">Coordinate System:</span>
          <span className="font-mono text-blue-400">LPI</span>
        </div>

        {/* Crosshair coordinates */}
        <div className="flex items-center gap-2">
          <span className="text-gray-500">Crosshair:</span>
          <span className="font-mono text-green-400">
            {formatCoord(crosshair.world_mm)}
          </span>
        </div>

        {/* Mouse hover coordinates */}
        {mouseCoord && (
          <div className="flex items-center gap-2">
            <span className="text-gray-500">Mouse:</span>
            <span className="font-mono text-yellow-400">
              {formatCoord(mouseCoord)}
            </span>
          </div>
        )}
      </div>

      {/* Optional right-side content */}
      <div className="flex items-center gap-4">
        {/* Could add GPU status, FPS, etc. here in the future */}
      </div>
    </div>
  );
}

